mapper.insert:
	INSERT INTO TBCODEBS (
		 COM_CD_ID		
		,CD_VAL		
		,LANG_CD		
		,CD_NM		
		,CD_VAL_NM		
		,CD_SEQ		
		,CD_DESC		
	) VALUES (
		 #{cdId, jdbcType = VARCHAR}
 		,#{cdVal, jdbcType = VARCHAR}
 		,#{langCd, jdbcType = VARCHAR}
 		,#{cdNm, jdbcType = VARCHAR}
 		,#{cdValNm, jdbcType = VARCHAR}
 		,#{cdSeq, jdbcType = NUMERIC}
 		,#{cdDesc, jdbcType = VARCHAR}
  	)

mapper.update:
	UPDATE TBCODEBS 
	SET
   		CD_NM = #{cdNm, jdbcType = VARCHAR}, 
  		CD_VAL_NM = #{cdValNm, jdbcType = VARCHAR}, 
  		CD_SEQ = #{cdSeq, jdbcType = NUMERIC}, 
  		CD_DESC = #{cdDesc, jdbcType = VARCHAR} 
	WHERE COM_CD_ID = #{cdId, jdbcType = VARCHAR}
	AND   CD_VAL = #{cdVal, jdbcType = VARCHAR}
	AND   LANG_CD = #{langCd, jdbcType = VARCHAR}

DELETE TBCODEBS
WHERE COM_CD_ID = #{cdId, jdbcType = VARCHAR}
AND   CD_VAL = #{cdVal, jdbcType = VARCHAR}
AND   LANG_CD = #{langCd, jdbcType = VARCHAR}
